class SoapUtil {
    static Document soapMessageToDocument(SOAPMessage msg) throws Exception {
        SOAPPart part = msg.getSOAPPart();
        return part.getEnvelope().getOwnerDocument();
    }

    static String soapMessageToString(SOAPMessage msg) throws Exception {
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        msg.writeTo(baos);
        return baos.toString("UTF-8");
    }

    static List<SignedElement> extractSignedElements(Document doc) {
        if (doc == null) return Collections.emptyList();

        Element envelope = doc.getDocumentElement();
        if (envelope == null) return Collections.emptyList();

        NodeList sigs = doc.getElementsByTagNameNS(WSConstants.SIG_NS, "Signature");
        if (sigs == null || sigs.getLength() == 0) return Collections.emptyList();

        List<SignedElement> out = new ArrayList<>();
        for (int i = 0; i < sigs.getLength(); i++) {
            Node sigNode = sigs.item(i);
            if (!(sigNode instanceof Element)) continue;
            Element sigEl = (Element) sigNode;

            NodeList refs = sigEl.getElementsByTagNameNS(WSConstants.SIG_NS, "Reference");
            for (int r = 0; r < refs.getLength(); r++) {
                Node refNode = refs.item(r);
                if (!(refNode instanceof Element)) continue;
                Element refEl = (Element) refNode;
                String uri = refEl.getAttribute("URI");
                if (uri == null || uri.isEmpty() || !uri.startsWith("#")) continue;
                String id = uri.substring(1);

                Element signedTarget = findElementByWsuId(doc, id);
                if (signedTarget == null) signedTarget = findElementByIdAny(doc, id);

                if (signedTarget != null) {
                    out.add(new SignedElement(
                            id,
                            signedTarget.getLocalName(),
                            signedTarget.getNamespaceURI(),
                            nodeToString(signedTarget)
                    ));
                }
            }
        }
        return out;
    }

    static Element findElementByWsuId(Document doc, String id) {
        if (doc == null || id == null) return null;
        NodeList all = doc.getElementsByTagName("*");
        for (int i = 0; i < all.getLength(); i++) {
            Node n = all.item(i);
            if (!(n instanceof Element)) continue;
            Element e = (Element) n;
            String wsuId = e.getAttributeNS(WSConstants.WSU_NS, "Id");
            if (id.equals(wsuId)) return e;
        }
        return null;
    }

    static Element findElementByIdAny(Document doc, String id) {
        if (doc == null || id == null) return null;
        NodeList all = doc.getElementsByTagName("*");
        for (int i = 0; i < all.getLength(); i++) {
            Node n = all.item(i);
            if (!(n instanceof Element)) continue;
            Element e = (Element) n;
            String v = e.getAttribute("Id");
            if (id.equals(v)) return e;
            v = e.getAttribute("ID");
            if (id.equals(v)) return e;
            v = e.getAttribute("id");
            if (id.equals(v)) return e;
        }
        return null;
    }

    static String nodeToString(Node node) {
        try {
            DOMImplementationLS ls = (DOMImplementationLS) node.getOwnerDocument().getImplementation().getFeature("LS", "3.0");
            LSSerializer ser = ls.createLSSerializer();
            ser.getDomConfig().setParameter("xml-declaration", false);
            return ser.writeToString(node);
        } catch (Exception e) {
            try {
                Transformer t = TransformerFactory.newInstance().newTransformer();
                ByteArrayOutputStream baos = new ByteArrayOutputStream();
                t.transform(new DOMSource(node), new StreamResult(baos));
                return baos.toString("UTF-8");
            } catch (Exception ex) {
                return null;
            }
        }
    }
}

class WSSecurityConfig {
    public static Map<String, Object> inboundProps(String cryptoPropsPath) {
        Map<String, Object> inProps = new HashMap<>();
        inProps.put(WSHandlerConstants.ACTION, WSHandlerConstants.SIGNATURE);
        inProps.put(WSHandlerConstants.SIG_PROP_FILE, cryptoPropsPath);
        inProps.put(WSHandlerConstants.SIG_KEY_ID, "DirectReference");
        inProps.put(WSHandlerConstants.SIG_ALGO, WSConstants.RSA_SHA256);
        inProps.put(WSHandlerConstants.SIG_DIGEST_ALGO, WSConstants.SHA256);
        inProps.put(WSHandlerConstants.ENABLE_SIGNATURE_CONFIRMATION, "false");
        inProps.put(WSHandlerConstants.MUST_UNDERSTAND, "true");
        inProps.put(WSHandlerConstants.IS_BSP_COMPLIANT, "true");
        inProps.put(WSHandlerConstants.ADD_INCLUSIVE_PREFIXES, "true");
        inProps.put(WSHandlerConstants.USE_SINGLE_CERTIFICATE, "true");
        return inProps;
    }

    public static Map<String, Object> outboundProps(String cryptoPropsPath, String keyAlias, String keyPassword) {
        Map<String, Object> outProps = new HashMap<>();
        outProps.put(WSHandlerConstants.ACTION, WSHandlerConstants.SIGNATURE);
        outProps.put(WSHandlerConstants.USER, keyAlias);
        outProps.put(WSHandlerConstants.SIG_PROP_FILE, cryptoPropsPath);
        outProps.put(WSHandlerConstants.PW_CALLBACK_REF, new StaticPasswordCallback(keyAlias, keyPassword));
        outProps.put(WSHandlerConstants.SIG_KEY_ID, "DirectReference");
        outProps.put(WSHandlerConstants.SIG_ALGO, WSConstants.RSA_SHA256);
        outProps.put(WSHandlerConstants.SIG_DIGEST_ALGO, WSConstants.SHA256);
        outProps.put(WSHandlerConstants.ADD_INCLUSIVE_PREFIXES, "true");
        outProps.put(WSHandlerConstants.USE_SINGLE_CERTIFICATE, "true");
        outProps.put(WSHandlerConstants.SIGNATURE_PARTS,
                "{Element}{" + WSConstants.URI_SOAP11_ENV + "}Body;" +
                        "{Element}{" + WSConstants.WSSE_NS + "}Security");
        return outProps;
    }
}

class StaticPasswordCallback implements org.apache.wss4j.common.ext.WSPasswordCallbackHandler {
    private final String alias;
    private final String password;

    StaticPasswordCallback(String alias, String password) {
        this.alias = alias;
        this.password = password;
    }

    @Override
    public void handle(org.apache.wss4j.common.ext.WSPasswordCallback[] callbacks) throws java.io.IOException, UnsupportedOperationException {
        if (callbacks == null) return;
        for (org.apache.wss4j.common.ext.WSPasswordCallback cb : callbacks) {
            if (cb == null) continue;
            if (Objects.equals(alias, cb.getIdentifier())) {
                cb.setPassword(password);
            }
        }
    }
}

class SignedElementsCaptureInInterceptor extends AbstractPhaseInterceptor<SoapMessage> {
    SignedElementsCaptureInInterceptor() {
        super(Phase.PRE_INVOKE);
    }

    @Override
    public void handleMessage(SoapMessage message) {
        try {
            SOAPMessage saaj = message.getContent(SOAPMessage.class);
            if (saaj == null) return;
            Document doc = SoapUtil.soapMessageToDocument(saaj);
            List<SignedElement> signed = SoapUtil.extractSignedElements(doc);
            message.put("bank.signedElements", signed);
        } catch (Exception ignored) {
        }
    }
}

public class BankingSoapServer {
    public static void main(String[] args) throws Exception {
        String address = System.getProperty("bank.ws.address", "http://0.0.0.0:8080/services/transactions");
        String cryptoProps = System.getProperty("bank.ws.crypto.props", "server-crypto.properties");
        String keyAlias = System.getProperty("bank.ws.key.alias", "serverkey");
        String keyPassword = System.getProperty("bank.ws.key.password", "changeit");

        BankingTransactionsService implementor = new BankingTransactionsService();

        JaxWsServerFactoryBean factory = new JaxWsServerFactoryBean();
        factory.setServiceClass(BankingTransactionsService.class);
        factory.setServiceBean(implementor);
        factory.setAddress(address);
        factory.getFeatures().add(new LoggingFeature());

        Map<String, Object> inProps = WSSecurityConfig.inboundProps(cryptoProps);
        Map<String, Object> outProps = WSSecurityConfig.outboundProps(cryptoProps, keyAlias, keyPassword);

        WSS4JInInterceptor wssIn = new WSS4JInInterceptor(inProps);
        WSS4JOutInterceptor wssOut = new WSS4JOutInterceptor(outProps);

        factory.getInInterceptors().add(new SAAJInInterceptor());
        factory.getInInterceptors().add(wssIn);
        factory.getInInterceptors().add(new SignedElementsCaptureInInterceptor());
        factory.getOutInterceptors().add(wssOut);

        factory.create();

        System.out.println("Banking SOAP service started at: " + address);
        Thread.currentThread().join();
    }
}